-- portal-a28: detalle (drill-down) del mes. pct hardcodeado 0.25 (interino; destino
-- configuracion_general). El mes viene normalizado en payload_norm ($1::jsonb->>'mes').
SELECT cuenta_corriente_detalle(($1::jsonb ->> 'mes')::date, pct_operativo_vigente()) AS detalle;

