// ===== portal-a28-cuenta-corriente-detalle — render JSON (drill-down L2) =====
// Passthrough del jsonb de cuenta_corriente_detalle (cascada, matriz, matriz_cabanas,
// incidencias, gastos_sin_incidencia). Read-only. El wrapper hardcodea pct=0.25, asi que el
// jsonb no trae 'error'; si lo trajera, se surfacea como payload_invalido.
function safeAll(nodeName) {
  try {
    const items = $(nodeName).all();
    const failed = items.some(it => it && it.json && (it.json.error || it.error));
    if (failed) return { ok: false, rows: [] };
    return { ok: true, rows: items.map(it => it.json) };
  } catch (e) { return { ok: false, rows: [] }; }
}

const r = safeAll('PG: leer detalle');
if (!r.ok || r.rows.length === 0) {
  return [{ json: { ok: false, error: { code: 'error_interno', message: 'no se pudo cargar el detalle', detail: null } } }];
}

const detalle = r.rows[0].detalle;
if (detalle && detalle.error) {
  return [{ json: { ok: false, error: { code: 'payload_invalido', message: String(detalle.error), detail: null } } }];
}

return [{ json: { ok: true, data: detalle } }];
